    def _pick_west_road_traveller_swap_target(self) -> str | None:
        """西大道旅者：选择场景区中与当前地区互换的地区。"""
        options = self._staging_location_pick_options()
        if not options:
            return None
        current_name = self.current_location_card.name
        dlg = CharacterImagePickDialog(
            self,
            '西大道旅者',
            f"{current_name}」互换的场景区地区：",
            options,
            mode="single",
            highlight_stat="health",
        )
        if dlg.exec_() != QDialog.Accepted:
            return None
