        dlg = CharacterImagePickDialog(
            self,
            '聚集力量',
            '选择一名英雄：从其资源池弃除 2 枚资源，'
            '再向该英雄资源池增加 3 枚资源（净 +1）：',
            options,
            mode="single",
            highlight_stat="attack",
        )
