        """骑向毁灭：弃除洛汗盟友 → 所选地区 +3 进度。"""
        ally_card, owner_idx = self._ally_on_field_by_id(ally_id)
        if ally_card is None or owner_idx is None:
            return '所选洛汗盟友已不在场'
        location = self._resolve_location_card(location_id)
        if location is None:
            return "所选地区已不在可选区域"
